patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 0632f3cfc6dd..6d75c0733499 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2618,9 +2618,23 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
       }
     }

+    Value *B;
+    if (match(Exp, m_ZExtOrSExt(m_Value(B))) &&
+        B->getType()->isIntOrIntVectorTy(1)) {
+      Type *Ty = II->getType();
+      Value *TrueVal = ConstantFP::get(Ty, 2.0);
+      Value *FalseVal = ConstantFP::get(Ty, 1.0);
+      if (match(Exp, m_SExt(m_Specific(B))))
+        TrueVal = ConstantFP::get(Ty, 0.5);
+      Value *Sel = Builder.CreateSelect(B, TrueVal, FalseVal);
+      // The FMul is created with Src on the LHS to avoid semantic matching
+      // issues with Alive2 timeout on fmul Select, Src.
+      Instruction *Mul = BinaryOperator::CreateFMul(Src, Sel);
+      Mul->copyFastMathFlags(II);
+      return Mul;
+    }
     break;
   }
-  case Intrinsic::ptrauth_auth:
   case Intrinsic::ptrauth_resign: {
     // (sign|resign) + (auth|resign) can be folded by omitting the middle
     // sign+auth component if the key and discriminator match.

